import re

# Simple OBO validation
try:
    with open('src/ontology/go-edit.obo', 'r') as f:
        content = f.read()

    # Check if our modifications are present
    if 'name: obsolete regulation of COPII vesicle coating' in content:
        print("✓ GO:0003400 obsoleted correctly")
    else:
        print("✗ GO:0003400 not obsoleted")

    if 'replaced_by: GO:0048208' in content and 'id: GO:0003400' in content:
        print("✓ GO:0003400 has replaced_by link")
    else:
        print("✗ GO:0003400 missing replaced_by")

    if 'name: COPII vesicle coat assembly' in content:
        print("✓ GO:0048208 renamed correctly")
    else:
        print("✗ GO:0048208 not renamed")

    if 'name: vesicle coat assembly' in content:
        print("✓ GO:0006901 renamed correctly")
    else:
        print("✗ GO:0006901 not renamed")

    # Check for basic OBO format issues
    if content.count('[Term]') > 30000:
        print("✓ Ontology file appears intact (has expected number of terms)")
    else:
        print("✗ Ontology file may be corrupted")

except Exception as e:
    print(f"Error: {e}")
EOF
